import pytest

def test_expense_claim_access_control_matrix(
    unauthenticated_api_client,
    forbidden_role_api_client,
    valid_expense_payload,
):
    # Row 1: unauthenticated -> 401
    resp_unauth = unauthenticated_api_client.post(
        "/expense-claims", json=valid_expense_payload
    )
    assert resp_unauth.status_code == 401, (
        f"Unauthenticated: expected 401, got {resp_unauth.status_code}"
    )

    # Row 2: wrong role -> 403
    resp_forbidden = forbidden_role_api_client.post(
        "/expense-claims", json=valid_expense_payload
    )
    assert resp_forbidden.status_code == 403, (
        f"Forbidden role: expected 403, got {resp_forbidden.status_code}"
    )
